import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/api';
import '../../styles/dashboard.css';

export const AdminDashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      setLoading(true);
      const response = await adminService.getSystemStats();
      // response.data = { success: true, data: {...} }
      // So we need response.data.data to get the actual stats
      setStats(response.data.data);
    } catch (err) {
      setError('Lỗi tải dữ liệu thống kê');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center" style={{ minHeight: '400px' }}>
          <div className="spinner"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>🔐 Quản lý Hệ thống</h1>
        <p>Tổng quan hệ thống quản lý ao tôm thông minh</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#dbeafe' }}>
            👥
          </div>
          <div className="stat-content">
            <p className="stat-label">Tổng người dùng</p>
            <p className="stat-value">{stats?.total_users || 0}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#dcfce7' }}>
            🏞️
          </div>
          <div className="stat-content">
            <p className="stat-label">Tổng ao nuôi</p>
            <p className="stat-value">{stats?.total_ponds || 0}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#fef3c7' }}>
            🌾
          </div>
          <div className="stat-content">
            <p className="stat-label">Tổng mùa vụ</p>
            <p className="stat-value">{stats?.total_seasons || 0}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ backgroundColor: '#fee2e2' }}>
            📊
          </div>
          <div className="stat-content">
            <p className="stat-label">Mùa vụ hoạt động</p>
            <p className="stat-value">{stats?.active_seasons || 0}</p>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="quick-actions">
        <h2>🚀 Chức năng quản lý</h2>
        
        {/* Section 1: Account Management */}
        <div className="actions-section">
          <h3>1️⃣ Quản lý tài khoản</h3>
          <div className="actions-grid">
            <a href="/admin/users" className="action-btn">
              <span className="action-icon">👥</span>
              <span className="action-label">Quản lý người dùng</span>
            </a>
          </div>
        </div>

        {/* Section 2: Master Data Management */}
        <div className="actions-section">
          <h3>2️⃣ Quản lý danh mục (Master Data)</h3>
          <div className="actions-grid">
            <a href="/admin/ponds" className="action-btn">
              <span className="action-icon">🏞️</span>
              <span className="action-label">Ao nuôi (Template)</span>
            </a>
            <a href="/admin/products?category=Thức ăn" className="action-btn">
              <span className="action-icon">🌾</span>
              <span className="action-label">Thức ăn</span>
            </a>
            <a href="/admin/products?category=Thuốc / Vi sinh" className="action-btn">
              <span className="action-icon">💊</span>
              <span className="action-label">Thuốc / Vi sinh</span>
            </a>
            <a href="/admin/diseases" className="action-btn">
              <span className="action-icon">🦠</span>
              <span className="action-label">Loại bệnh</span>
            </a>
            <a href="/admin/sensors" className="action-btn">
              <span className="action-icon">📊</span>
              <span className="action-label">Thiết bị cảm biến</span>
            </a>
          </div>
        </div>

        {/* Section 3: System Management */}
        <div className="actions-section">
          <h3>3️⃣ Quản lý hệ thống</h3>
          <div className="actions-grid">
            <a href="/admin/system" className="action-btn">
              <span className="action-icon">⚙️</span>
              <span className="action-label">Cài đặt hệ thống</span>
            </a>
            <a href="/admin/activity-logs" className="action-btn">
              <span className="action-icon">📊</span>
              <span className="action-label">Nhật ký hoạt động</span>
            </a>
            <a href="/admin/ai" className="action-btn">
              <span className="action-icon">🤖</span>
              <span className="action-label">Quản lý AI</span>
            </a>
          </div>
        </div>
      </div>

      {/* Recent Activities */}
      <div className="recent-section">
        <h2>📝 Thông tin bổ sung</h2>
        <div className="info-boxes">
          <div className="info-box">
            <h3>📌 Chính sách</h3>
            <ul>
              <li>✅ Quản trị toàn bộ hệ thống</li>
              <li>✅ Không tham gia vận hành ao</li>
              <li>✅ Không nhập nhật ký canh tác</li>
              <li>✅ Không chỉnh dữ liệu sản xuất</li>
            </ul>
          </div>

          <div className="info-box">
            <h3>⚡ Tính năng chính</h3>
            <ul>
              <li>✅ Quản lý tài khoản người dùng</li>
              <li>✅ Quản lý danh mục (Ao, Thức ăn, Thuốc, Bệnh, Cảm biến)</li>
              <li>✅ Quản lý model AI</li>
            </ul>
          </div>
        </div>
      </div>

      <style>{`
        .actions-section {
          margin-bottom: 30px;
        }

        .actions-section h3 {
          margin: 20px 0 15px 0;
          color: #374151;
          font-size: 16px;
          font-weight: 600;
          padding-bottom: 10px;
          border-bottom: 2px solid #e5e7eb;
        }

        .actions-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
          gap: 15px;
          margin-bottom: 20px;
        }

        .action-btn {
          padding: 20px;
          background: white;
          border: 2px solid #e5e7eb;
          border-radius: 8px;
          text-decoration: none;
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 10px;
          transition: all 0.3s;
          cursor: pointer;
        }

        .action-btn:hover {
          border-color: #3b82f6;
          box-shadow: 0 4px 12px rgba(59, 130, 246, 0.15);
          transform: translateY(-2px);
        }

        .action-icon {
          font-size: 32px;
        }

        .action-label {
          font-size: 13px;
          font-weight: 500;
          color: #374151;
          text-align: center;
          line-height: 1.3;
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;
